VALUES ('gap-policy-delivery-receipts', 'policy-v1.0.0', 'policy-08', 'SMS provider delivery receipts are not always final for ported numbers.', 'Medium', 'NonBlocking', 'Open', 'communications-manager', '2026-07-18T16:00:00-05:00', 'Pilot secondary delivery-status reconciliation.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO knowledge_gaps (knowledge_gap_id, procedure_version, step, statement, severity, blocking_kind, status, owner_role, identified_at, resolution_plan, semantic_type_iri)
VALUES ('gap-close-sod-unwitnessed', 'close-v1.1.0', 'close-05', 'req-close-separation stated the preparer may not be the final approver, but nothing evaluated it. The control existed only as prose in a Requirements row, so a violation would have been invisible.', 'High', 'Blocking', 'Resolved', 'controller', '2026-07-19T17:30:00-05:00', 'Resolved by StepExecutions.ViolatesSeparationOfDuties, which counts preparation steps in the same procedure execution performed by the agent now approving. Verified by staging a breach (maria-chen approving se-close05 after preparing se-close03): the witness read TRUE. The staged breach was reverted; the control now reads FALSE because separation genuinely holds, not because nothing is checking.', 'urn:effortless:pko-extension#KnowledgeGap') ON CONFLICT (knowledge_gap_id) DO UPDATE SET procedure_version = EXCLUDED.procedure_version, step = EXCLUDED.step, statement = EXCLUDED.statement, severity = EXCLUDED.severity, blocking_kind = EXCLUDED.blocking_kind, status = EXCLUDED.status, owner_role = EXCLUDED.owner_role, identified_at = EXCLUDED.identified_at, resolution_plan = EXCLUDED.resolution_plan, semantic_type_iri = EXCLUDED.semantic_type_iri;

