-- ----------------------------------------------------------------------------
-- WitnessLoops: One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop's predicates.
-- ----------------------------------------------------------------------------
INSERT INTO witness_loops (witness_loop_id, loop_number, title, premise, started_at, completed_at, semantic_type_iri)
VALUES ('loop-01', 1, 'The founding questions', 'The model specified obligations precisely and witnessed their breach almost nowhere. Requirements, verifications, exceptions, and communication policies were all stated with real precision, and in each case the execution-side counterpart that would catch a violation was missing. Loop 1 asks each of the twelve named roles what it actually needs to know, and invents the atomic predicates required to answer.', '2026-07-19T17:00:00-05:00', NULL, 'urn:effortless:pko-extension#WitnessLoop') ON CONFLICT (witness_loop_id) DO UPDATE SET loop_number = EXCLUDED.loop_number, title = EXCLUDED.title, premise = EXCLUDED.premise, started_at = EXCLUDED.started_at, completed_at = EXCLUDED.completed_at, semantic_type_iri = EXCLUDED.semantic_type_iri;

-- ----------------------------------------------------------------------------
-- RoleQuestions: One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.
-- ----------------------------------------------------------------------------
INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-blocking-unmet-on-my-step', 'finance-analyst', 'loop-01', 'On the steps I personally executed, did any of them close out while a BLOCKING requirement was still not fully satisfied?', 'I executed se-close03 (Reconcile material accounts), which carries TWO blocking requirements via sr-c03a (req-close-balance) and sr-c03b (req-close-evidence). Today the model records SatisfactionLevel as free text and nothing compares it against IsBlocking. If I close a step with a PartiallySatisfied blocking control — exactly the shape sat-policy-legal is in right now — the package moves on and nobody is told. I want that to be a computed red flag on my own row before it becomes an audit finding on my name.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-blocking-never-evaluated', 'finance-analyst', 'loop-01', 'Which blocking requirements were attached to a step I ran but never got a satisfaction record at all — not satisfied, not unsatisfied, just never assessed?', 'This is the failure mode that scares me more than a recorded ''Unsatisfied''. sr-c03b binds req-close-evidence to close-03. I ran close-03 as se-close03. There is no RequirementSatisfactions row for that pairing. The model shows green because absence reads as silence, not as a gap. An unevaluated blocking control is indistinguishable from a passed one, and that is the exact thing SOX testing is designed to catch.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-evidence-binding-stale', 'finance-analyst', 'loop-01', 'When I attested my reconciliation, was the underlying ledger data actually fresh — or was I certifying against a source that had already gone stale under its own SLA?', 'OperationalBindings.IsFresh already exists and works, but it is evaluated against NOW() and lives on a table nothing in the execution story reads. My step execution has no idea whether the resources it depended on were inside their freshness SLA. se-close02 already recorded a 17-minute feed against a 15-minute SLA and it took a human writing prose into a Deviation field to surface it. I want that connected structurally, because next time the prose might not get written.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-my-late-steps-unexplained', 'finance-analyst', 'loop-01', 'Which of my steps ran long without anybody recording why — and of those, which ones had an exception available that nobody invoked?', 'StepExecutions.IsLate already works. But ''late'' on its own is not a finding; late-and-unexplained is. se-close03 is mine and it ran nearly 19 hours. If that overran the expected duration and the Deviation field is empty, I have an undocumented overrun sitting on my name. And exc-ledger-outage exists precisely for the close-02 condition — if it was never invoked, the model should say that out loud instead of letting a blank Deviation stand in for ''nothing happened''.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-analyst-verification-declared-never-performed', 'finance-analyst', 'loop-01', 'For every step I ran that had a declared verification, did anybody actually perform it and record the observed signal — or did I just get a PASS with nothing behind it?', 'StepVerifications is entirely spec-side. verify-reconciliation declares that close-03 must show unexplained-material-variance = 0. I ran close-03. My StepExecution says VerificationResult=PASS. But there is no row anywhere recording what the signal ACTUALLY read. The PASS is an unbacked assertion typed into a field. If an auditor asks me to produce the observed value, the model has nothing — and a skipped verification looks identical to a passed one.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-separation-of-duties', 'controller', 'loop-01', 'Did the same agent both prepare and approve any part of this close? req-close-separation says the preparer may not be the final approver — show me that it actually held, on exec-close-2026-q2, computed and not asserted.', 'This is the single highest-value gap in the model and it is my control. req-close-separation is IsBlocking=true, bound to close-05 via sr-c05, and sat-close-separation records SatisfactionLevel=''Satisfied'' with the evidence string ''Preparer and reviewer were different agents.'' That string is a human typing a conclusion into a text field. NOTHING compares se-close03.ExecutedByAgent (maria-chen) against se-close05.ExecutedByAgent (devon-okafor) or se-close06.ExecutedByAgent (priya-raman). Segregation of duties is the control SOX cares about most and in this model it is prose. If maria-chen executed both the preparation and the approval tomorrow, sat-close-separation would still say ''Satisfied'' and the model would agree.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-approval-authority-valid', 'controller', 'loop-01', 'Every approval on this close — was it given by an agent who actually held the required role AT THE TIME they approved, not just someone who holds it today?', 'req-close-human-approval is blocking and says controller and CFO approvals must be human-confirmed. sat-close-human records ''Satisfied'' because a human name appears in a field. But nothing checks that the approving agent held the approving role. RoleAssignments proves this is not paranoia: ra-old-variance shows maria-chen held variance-review-agent until 2026-03-31 and ra-new-variance shows variance-ai took it on 2026-04-01. Role-holding is time-bounded and it genuinely changes. If someone approves close-06 who is not the CFO, or who was the CFO last quarter but not this one, I need that computed. And exc-cfo-unavailable explicitly permits delegation to an Acting CFO ''never to the preparer'' — so an authority check that cannot see delegation is incomplete.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-blocking-control-inoperative', 'controller', 'loop-01', 'Which of my blocking close controls are structurally incapable of failing — declared, bound to a step, and yet with no mechanism that could ever produce a negative result?', 'req-close-cutoff, req-close-balance, req-close-separation, and req-close-evidence are all IsBlocking=true. All four are pure prose. A control that cannot fail is not a control, it is a comment. Before I sign anything I want a list of my own controls ranked by whether they can actually operate. This is the meta-question — it is about the model''s ability to hold me accountable, and it is the one I would ask first if I were the external auditor rather than the controller.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-execution-diverged-from-spec', 'controller', 'loop-01', 'Give me one number per close: did exec-close-2026-q2 actually conform to close-v1.1.0, and if not, how far off was it?', 'ProcedureExecutions has ZERO derived fields. The parent of the entire execution story makes no claim whatsoever — it has a status someone typed and two timestamps. Every failure signal in this model lives on child rows, so to know whether a close was clean I have to read twelve StepExecutions and six RequirementSatisfactions by hand. That is not a control environment, that is a filing cabinet. I want conformance to be a computed property of the execution, so that ''the close was clean'' is a claim the model makes and can be wrong about.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

INSERT INTO role_questions (role_question_id, asking_role, witness_loop, question_text, why_it_matters, answerable_before, semantic_type_iri)
VALUES ('q-controller-ai-agent-approved-meaning', 'controller', 'loop-01', 'Did any AI agent or automated pipeline execute a step that requires human confirmation, or sign off on something a human was supposed to own?', 'req-close-human-approval and req-policy-human-approval both say a human must approve. Steps carries RequiresHumanConfirmation as a raw boolean and Agents carries AgentKind — Human, AIAgent, AutomatedPipeline — and NOTHING compares them. variance-ai executed se-close04. policy-drafting-ai executed se-policy03. Both fine today because those steps are not approval steps. But ra-old-variance to ra-new-variance shows this org actively migrates work from humans to AI agents, and the control that is supposed to stop that migration reaching an approval step is prose. This is the control I expect to matter most over the next two years and it currently does not exist.', FALSE, 'urn:effortless:pko-extension#RoleQuestion') ON CONFLICT (role_question_id) DO UPDATE SET asking_role = EXCLUDED.asking_role, witness_loop = EXCLUDED.witness_loop, question_text = EXCLUDED.question_text, why_it_matters = EXCLUDED.why_it_matters, answerable_before = EXCLUDED.answerable_before, semantic_type_iri = EXCLUDED.semantic_type_iri;

